        &lt;div class=&quot;form-section&quot;&gt;
            &lt;div class=&quot;form-section-title&quot;&gt;Profile photo&lt;/div&gt;

            &lt;div class=&quot;avatar-upload-row&quot;&gt;
                &lt;!-- Preview --&gt;
                &lt;div class=&quot;av-preview-wrap&quot;&gt;
