                             class=&quot;av-preview av-preview-initials&quot;
                             style=&quot;background:#ddeedd;color:#002D2D&quot;&gt;
                            ?                        &lt;/div&gt;
                        &lt;img id=&quot;av-preview-img&quot; class=&quot;av-preview av-preview-img&quot; style=&quot;display:none&quot; alt=&quot;Avatar preview&quot;&gt;
