                        &lt;div class=&quot;val-item&quot; id=&quot;v-ext&quot;&gt;&lt;i class=&quot;ti ti-circle-dashed&quot;&gt;&lt;/i&gt; Extension allowed&lt;/div&gt;
                    &lt;/div&gt;
