                           required
                           autocomplete=&quot;given-name&quot;&gt;
                                    &lt;/div&gt;

                &lt;div class=&quot;form-group &quot;&gt;
                    &lt;label class=&quot;form-label&quot; for=&quot;last_name&quot;&gt;Last name &lt;span class=&quot;req&quot;&gt;*&lt;/span&gt;&lt;/label&gt;
                    &lt;input type=&quot;text&quot;
                           id=&quot;last_name&quot;
                           name=&quot;last_name&quot;
                           value=&quot;&quot;
